import React from 'react';
import { Outlet } from 'react-router-dom';
import { Sidebar } from './Sidebar';
import { ChatBot } from './ChatBot';
import { ThemeProvider } from './ThemeContext';
import { LayoutProvider, useLayout } from './LayoutContext';

function DashboardInner() {
  const { collapsed, mobileOpen, setMobileOpen } = useLayout();

  return (
    <div className="min-h-screen bg-dash-bg font-sans transition-colors duration-200">
      {/* Mobile backdrop */}
      {mobileOpen && (
        <div
          className="fixed inset-0 bg-black/40 z-30 md:hidden"
          onClick={() => setMobileOpen(false)}
        />
      )}

      <Sidebar />

      {/* Responsive margin: 0 on mobile (sidebar is overlay), 64px or 240px on desktop */}
      <div className={`transition-all duration-300 ${collapsed ? 'md:ml-16' : 'md:ml-60'}`}>
        <Outlet />
      </div>

      <ChatBot />
    </div>
  );
}

export function DashboardLayout() {
  return (
    <ThemeProvider>
      <LayoutProvider>
        <DashboardInner />
      </LayoutProvider>
    </ThemeProvider>
  );
}

export default DashboardLayout;
